/// Represents the result of an operation that can either succeed with a value or fail with errors.
/// </summary>
/// <typeparam name="TValue">The type of the value returned on success.</typeparam>
public sealed record Result<TValue>
{
    private readonly TValue? _value;
    private readonly List<Error>? _errors;

    /// <summary>
    /// Gets a value indicating whether the operation was successful.
    /// </summary>
    public bool IsSuccess { get; }

    /// <summary>
    /// Gets the value if the operation was successful.
    /// </summary>
    /// <exception cref="InvalidOperationException">Thrown when accessed on a failed result.</exception>
    public TValue Value => IsSuccess 
        ? _value! 
        : throw new InvalidOperationException("Cannot access Value on a failed result.");

    /// <summary>
    /// Gets the collection of errors if the operation failed.
    /// </summary>
    public IReadOnlyList<Error> Errors => _errors ?? [];

    private Result(TValue value)
    {
        _value = value;
        IsSuccess = true;
        _errors = null;
    }

    private Result(List<Error> errors)
    {
        _errors = errors ?? throw new ArgumentNullException(nameof(errors));
        IsSuccess = false;
        _value = default;
    }

    /// <summary>
    /// Creates a successful result with the specified value.
    /// </summary>
    /// <param name="value">The value to wrap in the result.</param>
    /// <returns>A successful result containing the value.</returns>
    public static Result<TValue> Success(TValue value) => new(value);

    /// <summary>
    /// Creates a failed result with the specified errors.
    /// </summary>
    /// <param name="errors">The collection of errors.</param>
    /// <returns>A failed result containing the errors.</returns>
    public static Result<TValue> Failure(List<Error> errors) => new(errors);

    /// <summary>
    /// Creates a failed result with a single error.
    /// </summary>
    /// <param name="error">The error.</param>
    /// <returns>A failed result containing the error.</returns>
    public static Result<TValue> Failure(Error error) => new([error]);

    /// <summary>
    /// Creates a failed result with a single error from code and message.
    /// </summary>
    /// <param name="code">The error code.</param>
    /// <param name="message">The error message.</param>
    /// <returns>A failed result containing the error.</returns>
    public static Result<TValue> Failure
